                  {it.name} compró <span className="text-[#0A2A66] dark:text-[#5B9BD5] font-semibold">{it.product}</span>
                </div>
                <div className="text-xs text-slate-500 dark:text-slate-400">{timeAgoText(it.minutes)}</div>
