const STOPWORDS = new Set([
  'para',
  'de',
  'y',
  'con',
  'en',
  'a',
  'el',
  'la',
  'los',
  'las',
  'del',
  'por',
  'repuesto',
  'kit',
  'original',
  'nuevo',
